static void
initpath(const char *pathstr)
{

	if (pathstr == NULL)
		return;

	// Count the number of directories (number of colons + 1).
	const char *p;
	int count = 1;
	for (p = pathstr; *p != '\0'; p++) {
		if (*p == ':')
			count++;
	}

	searchpath = malloc(count * sizeof(char *));
	if (searchpath == NULL)
		unix_error("malloc error");

	// Make a mutable copy of pathstr for parsing.
	char *pathcopy = strdup(pathstr);
	if (pathcopy == NULL)
		unix_error("strdup error");

	npath = 0;
	char *token = pathcopy;
	char *colon;

	while ((colon = strchr(token, ':')) != NULL) {
		*colon = '\0';
		if (*token == '\0')
			searchpath[npath] = strdup(".");
		else
			searchpath[npath] = strdup(token);
		if (searchpath[npath] == NULL)
			unix_error("strdup error");
		npath++;
		token = colon + 1;
	}
	// Last entry (after last colon, or entire string if no colon).
	if (*token == '\0')
		searchpath[npath] = strdup(".");
	else
		searchpath[npath] = strdup(token);
	if (searchpath[npath] == NULL)
		unix_error("strdup error");
	npath++;

	free(pathcopy);
}

