static void
sigchld_handler(int signum)
{
	int olderrno = errno;
	pid_t pid;
	int status;

	// Prevent an "unused parameter" warning.
	(void)signum;

	while ((pid = waitpid(-1, &status, WNOHANG | WUNTRACED)) > 0) {
		if (WIFEXITED(status)) {
			// Child terminated normally.
			deletejob(jobs, pid);
		} else if (WIFSIGNALED(status)) {
			// Child terminated by uncaught signal.
			int jid = pid2jid(pid);
			Sio_puts("Job [");
			Sio_putl(jid);
			Sio_puts("] (");
			Sio_putl(pid);
			Sio_puts(") terminated by signal SIG");
			Sio_puts(signame[WTERMSIG(status)]);
			Sio_puts("\n");
			deletejob(jobs, pid);
		} else if (WIFSTOPPED(status)) {
			// Child stopped.
			JobP job = getjobpid(jobs, pid);
			int jid = pid2jid(pid);
			job->state = ST;
			Sio_puts("Job [");
			Sio_putl(jid);
			Sio_puts("] (");
			Sio_putl(pid);
			Sio_puts(") stopped by signal SIG");
			Sio_puts(signame[WSTOPSIG(status)]);
			Sio_puts("\n");
		}
	}

	errno = olderrno;
}

