static void
do_bgfg(char **argv)
{
	JobP job;
	char *id;
	long val;
	char *endptr;

	if (argv[1] == NULL) {
		printf("%s command requires PID or %%jobid argument\n",
		    argv[0]);
		return;
	}

	id = argv[1];

	if (id[0] == '%') {
		// JID argument.
		val = strtol(&id[1], &endptr, 10);
		if (*endptr != '\0' || endptr == &id[1]) {
			printf("%s: argument must be a PID or %%jobid\n",
			    argv[0]);
			return;
		}
		job = getjobjid(jobs, (int)val);
		if (job == NULL) {
			printf("%s: No such job\n", id);
			return;
		}
	} else if (isdigit(id[0])) {
		// PID argument.
		val = strtol(id, &endptr, 10);
		if (*endptr != '\0' || endptr == id) {
			printf("%s: argument must be a PID or %%jobid\n",
			    argv[0]);
			return;
		}
		job = getjobpid(jobs, (pid_t)val);
		if (job == NULL) {
			printf("(%ld): No such process\n", val);
			return;
		}
	} else {
		printf("%s: argument must be a PID or %%jobid\n", argv[0]);
		return;
	}

	// Send SIGCONT to the entire process group.
	kill(-(job->pid), SIGCONT);

	if (strcmp(argv[0], "bg") == 0) {
		job->state = BG;
		printf("[%d] (%d) %s", job->jid, (int)job->pid,
		    job->cmdline);
	} else {
		job->state = FG;
		waitfg(job->pid);
	}
}

