static void
eval(const char *cmdline)
{
	char *argv[MAXARGS];
	bool bg;
	pid_t pid;
	sigset_t mask, prev_mask;

	bg = parseline(cmdline, argv);

	// Ignore empty command lines.
	if (argv[0] == NULL)
		return;

	// Handle built-in commands.
	if (builtin_cmd(argv))
		return;

	// Block SIGCHLD before forking to avoid race condition.
	sigemptyset(&mask);
	sigaddset(&mask, SIGCHLD);
	sigprocmask(SIG_BLOCK, &mask, &prev_mask);

	pid = fork();
	if (pid < 0)
		unix_error("fork error");

	if (pid == 0) {
		// Child process.
		// Unblock SIGCHLD.
		sigprocmask(SIG_SETMASK, &prev_mask, NULL);

		// Put child in a new process group.
		setpgid(0, 0);

		// Determine the executable path.
		char *filename = argv[0];

		if (strchr(filename, '/') != NULL || searchpath == NULL) {
			// Name contains '/' or no search path: use directly.
			execve(filename, argv, environ);
			printf("%s: Command not found\n", filename);
			exit(0);
		} else {
			// Search PATH directories.
			char fullpath[MAXLINE];
			int i;
			for (i = 0; i < npath; i++) {
				snprintf(fullpath, MAXLINE, "%s/%s",
				    searchpath[i], filename);
				if (access(fullpath, X_OK) == 0) {
					execve(fullpath, argv, environ);
					// execve only returns on error.
					break;
				}
			}
			printf("%s: Command not found\n", filename);
			exit(0);
		}
