static bool
builtin_cmd(char **argv)
{

	if (strcmp(argv[0], "quit") == 0) {
		// Kill all background and stopped jobs before exiting.
		// This prevents sdriver.pl from hanging because children
		// still hold the stdout pipe FD open.
		int i;
		for (i = 0; i < MAXJOBS; i++) {
			if (jobs[i].pid != 0)
				kill(-jobs[i].pid, SIGTERM);
		}
		exit(0);
	}
	if (strcmp(argv[0], "jobs") == 0) {
		listjobs(jobs);
		return (true);
	}
	if (strcmp(argv[0], "bg") == 0 || strcmp(argv[0], "fg") == 0) {
		do_bgfg(argv);
		return (true);
	}
	return (false);     // This is not a built-in command.
}

