static void
waitfg(pid_t pid)
{
	sigset_t mask, prev;

	// Block SIGCHLD before checking fgpid to prevent race where
	// SIGCHLD arrives between the check and sigsuspend.
	sigemptyset(&mask);
	sigaddset(&mask, SIGCHLD);
	sigprocmask(SIG_BLOCK, &mask, &prev);

	while (fgpid(jobs) == pid)
		sigsuspend(&prev);

	sigprocmask(SIG_SETMASK, &prev, NULL);
}
